SELECT sn.id AS spec_name_id, sn.spec_name AS spec_name, sv.id AS spec_value_id, ref.sku_id AS sku_id, sv.spec_value AS spec_value, sv.status AS value_status FROM goods_sku_spec_ref ref LEFT JOIN goods_spec_value sv ON ref.spec_value_id = sv.id LEFT JOIN goods_spec_name sn ON sv.spec_id = sn.id WHERE ref.sku_id IN
#{skuId}
ORDER BY sn.sort DESC, sv.sort DESC

SELECT sn.id AS spec_name_id, sn.spec_name AS spec_name, sn.sort AS sort, sn.create_at AS created_at, sn.updated_at AS updated_at, ref.sku_id AS sku_id, sn.id AS spec_name_id_ref, sv.id AS spec_value_id, sv.spec_value AS spec_value, sv.sort AS value_sort, sv.status AS value_status, sv.create_at AS value_created_at, sv.updated_at AS value_updated_at FROM goods_sku_spec_ref ref LEFT JOIN goods_spec_value sv ON ref.spec_value_id = sv.id LEFT JOIN goods_spec_name sn ON sv.spec_id = sn.id WHERE ref.sku_id IN
#{skuId}
ORDER BY sn.sort DESC, sv.sort DESC

